INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('cnc-milling', 'equipment', '{"name": "Mazak I-600 5-Axis Machining", "description": "Our Mazak I-600 5-axis machining centers handle complex contoured geometry — impellers, turbine components, and multi-face aerospace brackets — in a single setup. Five-axis simultaneous motion eliminates repositioning error and holds ±0.01mm on critical features, making the Mazak I-600 our go-to for aerospace and medical parts that demand positional accuracy across multiple datums."}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('cnc-milling', 'equipment', '{"name": "DMG MORI 60EVO 5-Axis Machining", "description": "The DMG MORI 60EVO complements our 5-axis capacity with a 600 × 550 × 500mm work envelope, ideal for medium-sized precision housings and structural components. Its rigid construction and high-speed spindle deliver excellent surface finish on aluminum and titanium, reducing the need for secondary polishing."}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('cnc-milling', 'equipment', '{"name": "FANUC & Brother High-Speed 3-Axis Milling", "description": "For fast-turnaround precision parts and higher-volume runs, our FANUC a-D14MIA and Brother TC-S2DZ high-speed milling machines deliver rapid cycle times without sacrificing accuracy. These machines excel at small-to-medium aluminum and steel components — electronics enclosures, connectors, and brackets — where throughput and repeatability matter. With 70 Renishaw in-machine probes across the fleet, dimensions are verified during machining, not just after."}', 2);
