INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "CNC Milling", "description": "3-axis to 5-axis CNC milling on DMG MORI, Mazak, and Hermle. Tolerances to ±0.005mm on aluminum, steel, titanium, and engineering plastics.", "link": "cnc-milling.html", "icon": "fas fa-cog"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "CNC Turning", "description": "Swiss-type and conventional CNC lathes for shafts, bushings, connectors, and precision turned parts. Live tooling for milled features.", "link": "cnc-turning.html", "icon": "fas fa-sync-alt"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "5-Axis Machining", "description": "Simultaneous 5-axis on DMG MORI DMU 50 and Mazak Variaxis. Impellers, turbine blades, complex aerospace and medical geometries in one setup.", "link": "5-axis.html", "icon": "fas fa-cube"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Die Casting", "description": "High-pressure die casting in aluminum (A380, ADC12) and zinc alloys. From prototype tooling to high-volume production runs.", "link": "die-casting.html", "icon": "fas fa-fire"}', 3);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Investment Casting", "description": "Lost-wax investment casting in stainless steel, carbon steel, and copper alloys. Near-net shapes with excellent surface finish.", "link": "investment-casting.html", "icon": "fas fa-snowflake"}', 4);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Forging", "description": "Open-die and closed-die forging for high-strength structural components. Grain flow optimization for fatigue-critical parts.", "link": "forging.html", "icon": "fas fa-hammer"}', 5);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Sheet Metal", "description": "Laser cutting, CNC bending, welding, and finishing. Enclosures, brackets, chassis, and structural sheet metal assemblies.", "link": "sheet-metal.html", "icon": "fas fa-layer-group"}', 6);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Stamping", "description": "Progressive die and compound die stamping. High-volume contacts, brackets, shields, and electrical components.", "link": "stamping.html", "icon": "fas fa-stamp"}', 7);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Surface Finishing", "description": "Anodizing (Type II/III), powder coating, electroplating, passivation, polishing, sandblasting, and laser engraving — full in-house capability.", "link": "finishing.html", "icon": "fas fa-paint-roller"}', 8);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Assembly", "description": "Sub-assembly and full product assembly with bonded, fastened, and welded joining. Functional testing before shipment.", "link": "assembly.html", "icon": "fas fa-tools"}', 9);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Production Runs", "description": "Low- to mid-volume production with consistent quality and on-time delivery. PPAP documentation available for automotive and medical.", "link": "production.html", "icon": "fas fa-industry"}', 10);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('services', 'cards', '{"title": "Precision Inspection", "description": "Zeiss and Hexagon CMM inspection, optical measurement, surface roughness verification. Full First Article Inspection reports.", "link": "precision-inspection.html", "icon": "fas fa-search"}', 11);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Aerospace Parts", "description": "ISO9001 & IATF16949 certified manufacturing for flight-critical components. We deliver precision parts for commercial aviation, defense, and space applications with rigorous quality standards.", "link": "aerospace.html", "image": "/images/content/Aerospace_Parts_800x600.webp", "icon": "fas fa-plane"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Liquid Cooling Parts", "description": "High-precision thermal management components for data centers, EVs, and high-performance computing. Expert in complex cooling channel machining and heat sink manufacturing.", "link": "liquid-cooling.html", "image": "/images/content/Liquid_Cooling_Parts_800x600.webp", "icon": "fas fa-tint"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Medical Devices", "description": "Precision manufacturing for surgical instruments, implants, and diagnostic equipment. Cleanroom-compatible processes with full traceability documentation.", "link": "medical.html", "image": "/images/content/Medical_Devices_800x600.webp", "icon": "fas fa-heartbeat"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Electronics", "description": "Precision enclosures, heat sinks, and mechanical components for consumer electronics, telecommunications, and semiconductor equipment manufacturing.", "link": "electronics.html", "image": "/images/content/Electronics_Semiconductors_800x600.webp", "icon": "fas fa-microchip"}', 3);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Industrial Equipment", "description": "Heavy-duty components for manufacturing machinery, pumps, valves, and industrial automation systems. Built for durability and performance in demanding environments.", "link": "industrial.html", "image": "/images/content/Industrial_Equipment_800x600.webp", "icon": "fas fa-cogs"}', 4);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('industries', 'cards', '{"title": "Robotics & Automation", "description": "High-precision components for robotic arms, actuators, and automated systems. Supporting the next generation of manufacturing and service robotics.", "link": "robotics.html", "image": "/images/content/Robotics_Automation_800x600.webp", "icon": "fas fa-robot"}', 5);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'general', '{"question": "What file formats do you accept?", "answer": "We accept all major CAD formats including STEP (.STEP/.STP), IGES (.IGES/.IGS), STL, SolidWorks (.SLDPRT), Parasolid (.X_T), ACIS (.SAT), AutoCAD (.DWG/.DXF), PDF drawings, and ZIP archives with multiple files. If you have a different format, please contact us."}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'general', '{"question": "What is your typical lead time?", "answer": "Standard lead time is 7–10 business days. Expedited service is available at 10–15 days, and extended timelines (15–25 days) offer the most competitive pricing. Complex parts may require additional time."}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'general', '{"question": "Is there a minimum order quantity?", "answer": "No minimum order required. We handle everything from single prototypes to production runs of 100,000+ parts. Our pricing is competitive at any volume."}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'technical', '{"question": "What tolerances can you achieve?", "answer": "Standard tolerances are ±0.005\\" (0.127mm). Precision tolerances to ±0.005mm (±0.0002\\") are available for critical features. Tighter tolerances may be possible depending on geometry."}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'technical', '{"question": "What materials do you work with?", "answer": "We machine 50+ materials including aluminum alloys, stainless steel, steel, titanium, brass, copper, engineering plastics (Delrin, PEEK, Ultem, Nylon), and exotic alloys (Inconel, Hastelloy)."}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'technical', '{"question": "What certifications do you hold?", "answer": "We are ISO9001 and IATF16949 certified. We provide complete quality documentation including inspection reports, material certifications, and certificates of conformance."}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'ordering', '{"question": "Do you offer finishing services?", "answer": "Yes, we offer anodizing (Type II & III), powder coating, plating, passivation, bead blasting, electropolishing, and more. All finishing is done in-house for quality control."}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('faq', 'ordering', '{"question": "Do you ship internationally?", "answer": "Yes, we ship worldwide. We have experience with international shipping and can handle export documentation. DHL, FedEx, and UPS options are available."}', 1);
