INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('case-studies', 'cases', '{"industry": "Aerospace", "title": "Titanium Turbine Component", "image": "", "icon": "fas fa-plane", "description": "An aerospace OEM required complex titanium components for a new turbine design. The parts featured thin walls, tight tolerances, and demanding surface finish requirements.", "challenge": "Titanium machining with ±0.005mm tolerances and Ra 16 μin surface finish", "solution": "5-axis simultaneous machining with specialized tooling and coolant strategies", "stat1_value": "40%", "stat1_label": "Cost Reduction", "stat2_value": "100%", "stat2_label": "First Pass Yield", "stat3_value": "3 Weeks", "stat3_label": "Lead Time"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('case-studies', 'cases', '{"industry": "Medical", "title": "Surgical Instrument Components", "image": "", "icon": "fas fa-heartbeat", "description": "A medical device company needed high-volume production of stainless steel surgical instrument components with full traceability and documentation.", "challenge": "316L stainless with mirror finish and complete lot traceability", "solution": "Automated production cells with integrated inspection and barcode tracking", "stat1_value": "50K+", "stat1_label": "Parts/Month", "stat2_value": "0.02%", "stat2_label": "Defect Rate", "stat3_value": "100%", "stat3_label": "Traceability"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('case-studies', 'cases', '{"industry": "Electronics", "title": "Liquid Cooling Heat Sink", "image": "", "icon": "fas fa-microchip", "description": "A data center equipment manufacturer required high-performance liquid cooling heat sinks with complex internal channels for server cooling applications.", "challenge": "Complex internal cooling channels with leak-proof brazed assembly", "solution": "Multi-piece CNC machining with vacuum brazing and 100% pressure testing", "stat1_value": "30%", "stat1_label": "Better Cooling", "stat2_value": "0", "stat2_label": "Leak Failures", "stat3_value": "2 Years", "stat3_label": "Partnership"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('case-studies', 'cases', '{"industry": "Robotics", "title": "Robotic Arm Joint Assembly", "image": "", "icon": "fas fa-robot", "description": "A robotics startup needed precision aluminum components for their new collaborative robot arm, with fast iteration cycles during development.", "challenge": "Rapid prototyping with design iterations and smooth transition to production", "solution": "Agile manufacturing with DFM feedback and scalable production processes", "stat1_value": "15", "stat1_label": "Iterations", "stat2_value": "5 Days", "stat2_label": "Avg. Turnaround", "stat3_value": "Scale-up", "stat3_label": "To Production"}', 3);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'electroplating', '{"title": "Zinc Plating", "icon": "fas fa-shield-alt", "description": "Electrochemical process that deposits a protective zinc layer on steel and iron parts, providing excellent corrosion resistance through sacrificial protection.", "features": "Excellent corrosion resistance\\nCost-effective protection\\nVarious finishes: clear, yellow, black\\nRoHS compliant options available", "applications": "Fasteners, brackets, automotive parts, hardware"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'electroplating', '{"title": "Nickel Plating", "icon": "fas fa-gem", "description": "Creates a hard, lustrous coating that provides excellent wear resistance and decorative appeal. Available in bright, satin, and electroless variants.", "features": "High wear resistance\\nAttractive bright or satin finish\\nGood corrosion protection\\nExcellent base for other coatings", "applications": "Electronics, decorative parts, industrial components"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'electroplating', '{"title": "Chrome Plating", "icon": "fas fa-star", "description": "Deposits a hard chromium layer providing superior hardness, excellent wear resistance, and a brilliant decorative finish with low friction coefficient.", "features": "Extremely high hardness (HV 800-1000)\\nSuperior wear resistance\\nBrilliant decorative appearance\\nLow coefficient of friction", "applications": "Hydraulic cylinders, molds, decorative trim, tools"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'electroplating', '{"title": "Copper Plating", "icon": "fas fa-plug", "description": "Deposits a copper layer that provides excellent electrical conductivity, often used as a base layer for subsequent plating or for its conductive properties.", "features": "Excellent electrical conductivity\\nGood heat conductivity\\nIdeal undercoat for multi-layer plating\\nImproves adhesion of top coats", "applications": "Electronics, EMI shielding, decorative base layer"}', 3);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'chemical-treatment', '{"title": "Blackening / Black Oxide", "icon": "fas fa-moon", "description": "Chemical conversion process that produces a black magnetite (Fe3O4) layer on steel and iron parts, providing rust prevention and aesthetic appeal.", "features": "Rust prevention for ferrous metals\\nMinimal dimensional change\\nAttractive matte black finish\\nReduces light reflection", "applications": "Tools, fasteners, machine components, firearms"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'chemical-treatment', '{"title": "Phosphating", "icon": "fas fa-layer-group", "description": "Creates a crystalline phosphate conversion coating that enhances paint adhesion, provides moderate corrosion protection, and improves lubricity.", "features": "Excellent paint adhesion\\nCorrosion protection\\nImproved lubricant retention\\nTypes: zinc, manganese, iron phosphate", "applications": "Automotive bodies, appliances, pre-paint treatment"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'chemical-treatment', '{"title": "Passivation", "icon": "fas fa-shield-virus", "description": "Chemical treatment for stainless steel that removes free iron and enhances the natural chromium oxide layer, maximizing corrosion resistance.", "features": "Enhances corrosion resistance\\nRemoves surface contaminants\\nNo dimensional change\\nASTM A967 / AMS2700 compliant", "applications": "Medical devices, food equipment, aerospace parts"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'chemical-treatment', '{"title": "Electroless Nickel Plating", "icon": "fas fa-atom", "description": "Autocatalytic chemical process that deposits uniform nickel-phosphorus alloy without external electrical current, ideal for complex geometries.", "features": "Uniform thickness on complex shapes\\nExcellent corrosion resistance\\nNo edge buildup\\nCan plate non-conductive substrates", "applications": "Valves, pumps, electronics, oil & gas equipment"}', 3);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'anodizing', '{"title": "Type II Anodizing (Decorative)", "icon": "fas fa-palette", "description": "Standard sulfuric acid anodizing that creates a porous oxide layer suitable for dyeing. Provides good corrosion resistance and aesthetic appeal.", "features": "Thickness: 8-25μm\\nWide range of colors available\\nGood corrosion resistance\\nModerate wear resistance", "applications": "Consumer electronics, architectural, automotive trim"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'anodizing', '{"title": "Type III Anodizing (Hard Coat)", "icon": "fas fa-hammer", "description": "Hard anodizing process that produces a much thicker, harder, and more wear-resistant oxide layer for demanding applications.", "features": "Thickness: 25-100μm\\nSuperior hardness (60-70 HRC equivalent)\\nExcellent wear resistance\\nNatural gray-black color", "applications": "Military, aerospace, hydraulic components, firearms"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'heat-treatment', '{"title": "Carburizing", "icon": "fas fa-temperature-high", "description": "Diffuses carbon into the surface of low-carbon steel at high temperature, creating a hard, wear-resistant case while maintaining a tough, ductile core.", "features": "Case depth: 0.5-2.0mm typical\\nSurface hardness: 58-62 HRC\\nExcellent fatigue resistance\\nMaintains core toughness", "applications": "Gears, shafts, bearings, camshafts"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'heat-treatment', '{"title": "Nitriding", "icon": "fas fa-wind", "description": "Diffuses nitrogen into the surface at lower temperatures than carburizing, creating extremely hard surface layer with excellent wear and fatigue resistance.", "features": "Surface hardness: 65-70 HRC equivalent\\nMinimal distortion (low temperature)\\nNo quenching required\\nExcellent corrosion resistance", "applications": "Molds, dies, crankshafts, valve components"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'heat-treatment', '{"title": "Induction Hardening", "icon": "fas fa-broadcast-tower", "description": "Rapid localized heat treatment using high-frequency electromagnetic induction, followed by quenching to harden specific surface areas while minimizing distortion.", "features": "Precise, localized hardening\\nFast process cycle\\nMinimal distortion\\nSelective area treatment", "applications": "Shafts, gears, spindles, bearing races"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'mechanical', '{"title": "Polishing", "icon": "fas fa-star", "description": "Progressive abrasive process to achieve mirror-like surface finishes with extremely low roughness values. Includes mechanical, chemical, and electropolishing methods.", "features": "Mirror finish (Ra < 0.1μm possible)\\nManual or automated processes\\nElectropolishing available\\nRemoves surface imperfections", "applications": "Medical devices, optics, decorative parts, molds"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'mechanical', '{"title": "Sandblasting / Bead Blasting", "icon": "fas fa-cloud", "description": "High-pressure abrasive media treatment to create uniform matte textures, remove burrs, clean surfaces, and prepare for subsequent finishing processes.", "features": "Uniform matte finish\\nEffective deburring\\nSurface preparation\\nVarious grit sizes available", "applications": "Consumer electronics, enclosures, pre-anodizing treatment"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'mechanical', '{"title": "Brushing / Hairline Finish", "icon": "fas fa-align-left", "description": "Creates directional linear texture (hairline pattern) on metal surfaces using abrasive belts or brushes, providing distinctive metallic appearance.", "features": "Distinctive linear texture\\nHides fingerprints and scratches\\nVarious grain patterns\\nProfessional metallic appearance", "applications": "Appliances, consumer electronics, architectural panels"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'marking-printing', '{"title": "Laser Engraving", "icon": "fas fa-crosshairs", "description": "Uses focused laser beam to ablate material surface, creating permanent high-precision marks. Non-contact process ideal for delicate parts and high-volume production.", "features": "High precision marking\\nPermanent, wear-resistant\\nNo contact with workpiece\\nFast cycle time for batch production\\nVariable depth control", "applications": "Logos, serial numbers, QR codes, button markings, traceability"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'marking-printing', '{"title": "Screen Printing (Silk Screen)", "icon": "fas fa-print", "description": "Transfers ink through a fine mesh screen onto the workpiece surface. Cost-effective for large batches with vibrant colors and good ink coverage.", "features": "Cost-effective for high volumes\\nVibrant colors available\\nMulti-color printing possible\\nThick ink layer, good coverage\\nOn-site capability at our facility", "applications": "Control panels, button text, decorative patterns, labels"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'marking-printing', '{"title": "Pad Printing", "icon": "fas fa-stamp", "description": "Indirect offset printing using silicone pad to transfer ink from etched plate to irregular or curved surfaces not suitable for screen printing.", "features": "Prints on curved surfaces\\nFine detail reproduction\\nMulti-color capability\\nHandles complex geometries", "applications": "Medical devices, electronics, promotional products"}', 2);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'other-specialty', '{"title": "Dacromet", "icon": "fas fa-leaf", "description": "Chrome-free, environmentally friendly anti-corrosion coating using zinc and aluminum flakes in an inorganic binder. Provides excellent corrosion protection without hexavalent chromium.", "features": "Chrome-free, RoHS compliant\\nExcellent corrosion resistance\\nNo hydrogen embrittlement\\nHeat resistant to 300°C\\nEnvironmentally friendly", "applications": "Automotive fasteners, brake components, wind turbine bolts"}', 0);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'other-specialty', '{"title": "Teflon / PTFE Coating", "icon": "fas fa-shield-alt", "description": "Fluoropolymer coating providing extremely low friction coefficient, chemical resistance, and non-stick properties for demanding applications.", "features": "Lowest friction coefficient\\nNon-stick surface\\nChemical resistance\\nWide temperature range", "applications": "Molds, food processing, medical, bearings"}', 1);
INSERT INTO cms_collections (page, collection, item_data, sort_order) VALUES ('finishing', 'other-specialty', '{"title": "Chromate Conversion", "icon": "fas fa-palette", "description": "Chemical treatment for aluminum that provides corrosion protection and improves paint adhesion. Available in clear (RoHS) and yellow/iridescent versions.", "features": "Corrosion protection for aluminum\\nExcellent paint adhesion\\nConductive surface maintained\\nRoHS compliant options", "applications": "Aerospace, electronics, military, pre-paint treatment"}', 2);
